// Originally generated by CLI Printing Press; extended in polish to support
// remote (Streamable HTTP) transport in addition to stdio per Anthropic's
// 2026-04 MCP guidance. The runtime mode is controlled by the
// PRODUCT_HUNT_MCP_TRANSPORT env var (stdio | http) and PRODUCT_HUNT_MCP_ADDR
// (when transport=http; default ":8080"). Default behavior is unchanged
// (stdio) so existing local installs keep working.

package main

import (
	"fmt"
	"os"

	"github.com/mark3labs/mcp-go/server"
	mcptools "github.com/mvanhorn/printing-press-library/library/marketing/producthunt/internal/mcp"
)

func main() {
	s := server.NewMCPServer(
		"Product Hunt",
		"1.0.0",
		server.WithToolCapabilities(false),
	)
	mcptools.RegisterTools(s)

	transport := os.Getenv("PRODUCT_HUNT_MCP_TRANSPORT")
	if transport == "" {
		transport = "stdio"
	}

	switch transport {
	case "stdio":
		if err := server.ServeStdio(s); err != nil {
			fmt.Fprintf(os.Stderr, "MCP server error: %v\n", err)
			os.Exit(1)
		}
	case "http":
		addr := os.Getenv("PRODUCT_HUNT_MCP_ADDR")
		if addr == "" {
			addr = ":8080"
		}
		http := server.NewStreamableHTTPServer(s)
		fmt.Fprintf(os.Stderr, "Product Hunt MCP server listening (Streamable HTTP) on %s/mcp\n", addr)
		if err := http.Start(addr); err != nil {
			fmt.Fprintf(os.Stderr, "MCP HTTP server error: %v\n", err)
			os.Exit(1)
		}
	default:
		fmt.Fprintf(os.Stderr, "Unknown PRODUCT_HUNT_MCP_TRANSPORT=%q (expected stdio | http)\n", transport)
		os.Exit(2)
	}
}
